import { describe, expect, it } from "vitest";
import { mergeIntervals } from "../src/merge.js";

// A structural clone of an interval list, used to assert non-mutation of inputs.
const clone = (intervals) => intervals.map(([s, e]) => [s, e]);

describe("mergeIntervals", () => {
  describe("empty and singleton inputs", () => {
    it("returns [] for an empty input", () => {
      expect(mergeIntervals([])).toEqual([]);
    });

    it("returns a single interval unchanged", () => {
      expect(mergeIntervals([[1, 4]])).toEqual([[1, 4]]);
    });

    it("preserves a degenerate zero-length interval ([5,5])", () => {
      expect(mergeIntervals([[5, 5]])).toEqual([[5, 5]]);
    });
  });

  describe("overlapping intervals are merged", () => {
    it("merges the documented example [1,4],[3,6] -> [1,6]", () => {
      expect(mergeIntervals([[1, 4], [3, 6]])).toEqual([[1, 6]]);
    });

    it("merges when one interval fully contains another", () => {
      expect(mergeIntervals([[1, 10], [3, 6]])).toEqual([[1, 10]]);
    });

    it("keeps the widest end when a later interval ends earlier", () => {
      // [1,8] should absorb [2,4] without shrinking to end=4.
      expect(mergeIntervals([[1, 8], [2, 4]])).toEqual([[1, 8]]);
    });

    it("chains a cascade of overlaps into one interval", () => {
      expect(mergeIntervals([[1, 3], [2, 5], [4, 8], [7, 10]])).toEqual([[1, 10]]);
    });

    it("merges duplicate identical intervals", () => {
      expect(mergeIntervals([[2, 4], [2, 4], [2, 4]])).toEqual([[2, 4]]);
    });
  });

  describe("touching intervals are merged", () => {
    it("merges the documented example [1,2],[2,3] -> [1,3]", () => {
      expect(mergeIntervals([[1, 2], [2, 3]])).toEqual([[1, 3]]);
    });

    it("merges a zero-length interval that touches its neighbor", () => {
      expect(mergeIntervals([[1, 5], [5, 5]])).toEqual([[1, 5]]);
      expect(mergeIntervals([[5, 5], [5, 9]])).toEqual([[5, 9]]);
    });
  });

  describe("disjoint intervals stay separate", () => {
    it("keeps a gap between non-touching intervals", () => {
      expect(mergeIntervals([[1, 2], [4, 5]])).toEqual([[1, 2], [4, 5]]);
    });

    it("does not merge intervals separated by a unit gap", () => {
      // end=2 and start=3 do not touch (2 < 3), so they stay separate.
      expect(mergeIntervals([[1, 2], [3, 4]])).toEqual([[1, 2], [3, 4]]);
    });

    it("keeps many disjoint intervals in order", () => {
      expect(mergeIntervals([[1, 2], [4, 5], [7, 8]])).toEqual([
        [1, 2],
        [4, 5],
        [7, 8],
      ]);
    });
  });

  describe("output is sorted by start ascending", () => {
    it("sorts a reversed input", () => {
      expect(mergeIntervals([[7, 8], [4, 5], [1, 2]])).toEqual([
        [1, 2],
        [4, 5],
        [7, 8],
      ]);
    });

    it("merges out-of-order overlapping intervals after sorting", () => {
      expect(mergeIntervals([[3, 6], [1, 4]])).toEqual([[1, 6]]);
    });

    it("handles a shuffled mix of overlapping and disjoint intervals", () => {
      const input = [[15, 18], [1, 3], [8, 10], [2, 6], [9, 12]];
      expect(mergeIntervals(input)).toEqual([
        [1, 6],
        [8, 12],
        [15, 18],
      ]);
    });

    it("orders intervals that share a start by processing them together", () => {
      expect(mergeIntervals([[1, 4], [1, 2], [1, 6]])).toEqual([[1, 6]]);
    });
  });

  describe("negative and mixed-sign values", () => {
    it("merges intervals spanning zero", () => {
      expect(mergeIntervals([[-5, 0], [-1, 3]])).toEqual([[-5, 3]]);
    });

    it("sorts and merges negative intervals correctly", () => {
      expect(mergeIntervals([[-2, -1], [-10, -5], [-6, -3]])).toEqual([
        [-10, -3],
        [-2, -1],
      ]);
    });
  });

  describe("non-integer values", () => {
    it("merges fractional intervals", () => {
      expect(mergeIntervals([[1.5, 2.5], [2.5, 3.0]])).toEqual([[1.5, 3.0]]);
    });

    it("treats a tiny gap between floats as disjoint", () => {
      expect(mergeIntervals([[1.0, 2.0], [2.1, 3.0]])).toEqual([
        [1.0, 2.0],
        [2.1, 3.0],
      ]);
    });
  });

  describe("invalid intervals throw RangeError", () => {
    it("throws when a pair has start > end", () => {
      expect(() => mergeIntervals([[5, 1]])).toThrow(RangeError);
    });

    it("includes the offending interval in the message", () => {
      expect(() => mergeIntervals([[5, 1]])).toThrow("invalid interval [5, 1]");
    });

    it("throws when any pair in the list is invalid", () => {
      expect(() => mergeIntervals([[1, 2], [9, 3], [4, 5]])).toThrow(RangeError);
    });

    it("throws before producing any output for a mixed valid/invalid list", () => {
      let result;
      expect(() => {
        result = mergeIntervals([[1, 2], [8, 6]]);
      }).toThrow(RangeError);
      expect(result).toBeUndefined();
    });

    it("does not throw for a valid zero-length interval (start == end)", () => {
      expect(() => mergeIntervals([[3, 3]])).not.toThrow();
    });
  });

  describe("input is never mutated", () => {
    it("does not mutate the outer array", () => {
      const input = [[1, 4], [3, 6], [8, 9]];
      const before = clone(input);
      mergeIntervals(input);
      expect(input).toEqual(before);
      expect(input.length).toBe(3);
    });

    it("does not mutate the individual pairs", () => {
      const input = [[1, 8], [2, 4]];
      mergeIntervals(input);
      expect(input).toEqual([[1, 8], [2, 4]]);
    });

    it("returns a result that is independent of the input pairs", () => {
      const input = [[1, 4], [3, 6]];
      const result = mergeIntervals(input);
      // Mutating the result must not reach back into the input.
      result[0][0] = 999;
      expect(input).toEqual([[1, 4], [3, 6]]);
    });

    it("returns a new array, not the input reference", () => {
      const input = [[1, 2]];
      expect(mergeIntervals(input)).not.toBe(input);
    });
  });

  describe("larger and stress-style inputs", () => {
    it("merges a long run of overlapping intervals into one", () => {
      const input = Array.from({ length: 100 }, (_, i) => [i, i + 2]);
      expect(mergeIntervals(input)).toEqual([[0, 101]]);
    });

    it("keeps a long run of disjoint intervals separate", () => {
      const input = Array.from({ length: 50 }, (_, i) => [i * 10, i * 10 + 1]);
      const result = mergeIntervals(input);
      expect(result.length).toBe(50);
      expect(result).toEqual(input);
    });
  });
});

